import{_ as o,o as t,c as a,a4 as r}from"./chunks/framework.BFb8hfFA.js";const u=JSON.parse('{"title":"Interface: HostOptions · core","description":"","frontmatter":{"title":"Interface: HostOptions · core"},"headers":[],"relativePath":"api/core/interfaces/HostOptions.md","filePath":"api/core/interfaces/HostOptions.md"}'),s={name:"api/core/interfaces/HostOptions.md"};function n(d,e,i,c,l,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<p><a href="./../">@jsvision/core</a> / HostOptions</p><h1 id="interface-hostoptions" tabindex="-1">Interface: HostOptions <a class="header-anchor" href="#interface-hostoptions" aria-label="Permalink to &quot;Interface: HostOptions&quot;">​</a></h1><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L28" target="_blank" rel="noreferrer">host/types.ts:28</a></p><p>Options for <a href="./../functions/createHost.html">createHost</a>. Only <code>caps</code> is required; every OS-touching input is injectable, so the same host can be driven against real streams or fakes in tests.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="adaptambiguouswidth" tabindex="-1">adaptAmbiguousWidth? <a class="header-anchor" href="#adaptambiguouswidth" aria-label="Permalink to &quot;adaptAmbiguousWidth?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>adaptAmbiguousWidth?</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L74" target="_blank" rel="noreferrer">host/types.ts:74</a></p><p>Automatically switch to ASCII-safe chrome when the startup width probe finds that box/scroll glyphs render two cells wide: wide arrows turn on the <code>ambiguousWide</code> glyph flag, wide box/shade glyphs turn <code>boxDrawing</code>/<code>halfBlocks</code> off — so every frame stays aligned instead of shearing. Downgrade-only; the original caps are still used for input decoding, mode setup, and restore. Real TTY only, and it shares the single probe run with <a href="#warnambiguouswidth">warnAmbiguousWidth</a>. Default <code>false</code> (the higher-level app runner turns this on).</p><hr><h3 id="caps" tabindex="-1">caps <a class="header-anchor" href="#caps" aria-label="Permalink to &quot;caps&quot;">​</a></h3><blockquote><p><code>readonly</code> <strong>caps</strong>: <a href="./CapabilityProfile.html"><code>CapabilityProfile</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L30" target="_blank" rel="noreferrer">host/types.ts:30</a></p><p>The detected capability profile; gates every terminal mode the host enables.</p><hr><h3 id="env" tabindex="-1">env? <a class="header-anchor" href="#env" aria-label="Permalink to &quot;env?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>env?</strong>: <code>ProcessEnv</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L81" target="_blank" rel="noreferrer">host/types.ts:81</a></p><p>Environment to read the <code>JSVISION_ASCII</code> force switch from (NO_COLOR-style: its mere presence, with any value, turns it on). When set, the host renders fully ASCII-safe chrome and skips the width probe entirely. Default <code>process.env</code>. Presence-checked only — the value is never parsed or logged.</p><hr><h3 id="exitonsignal" tabindex="-1">exitOnSignal? <a class="header-anchor" href="#exitonsignal" aria-label="Permalink to &quot;exitOnSignal?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>exitOnSignal?</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L48" target="_blank" rel="noreferrer">host/types.ts:48</a></p><p>When false, terminating signals restore the terminal but do not call <code>process.exit</code>. Default true.</p><hr><h3 id="focus" tabindex="-1">focus? <a class="header-anchor" href="#focus" aria-label="Permalink to &quot;focus?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>focus?</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L54" target="_blank" rel="noreferrer">host/types.ts:54</a></p><p>Enable focus reporting (the terminal reports when it gains/loses focus). No capability models this, so it is a host policy rather than caps-gated. Default <code>true</code>.</p><hr><h3 id="input" tabindex="-1">input? <a class="header-anchor" href="#input" aria-label="Permalink to &quot;input?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>input?</strong>: <code>ReadStream</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L32" target="_blank" rel="noreferrer">host/types.ts:32</a></p><p>Input stream to read from. Default: <code>process.stdin</code> (or <code>/dev/tty</code> when stdout is piped).</p><hr><h3 id="onbeforeexit" tabindex="-1">onBeforeExit? <a class="header-anchor" href="#onbeforeexit" aria-label="Permalink to &quot;onBeforeExit?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>onBeforeExit?</strong>: (<code>code</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L46" target="_blank" rel="noreferrer">host/types.ts:46</a></p><p>Runs just before the host calls <code>process.exit</code> on a signal or crash path (receives the exit code).</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="code" tabindex="-1">code <a class="header-anchor" href="#code" aria-label="Permalink to &quot;code&quot;">​</a></h5><p><code>number</code></p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="oninput" tabindex="-1">onInput? <a class="header-anchor" href="#oninput" aria-label="Permalink to &quot;onInput?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>onInput?</strong>: (<code>event</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L38" target="_blank" rel="noreferrer">host/types.ts:38</a></p><p>Called with each decoded input event. Terminal query replies are handled internally and never delivered here.</p><h4 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="event" tabindex="-1">event <a class="header-anchor" href="#event" aria-label="Permalink to &quot;event&quot;">​</a></h5><p><a href="./../type-aliases/InputEvent.html"><code>InputEvent</code></a></p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="onresize" tabindex="-1">onResize? <a class="header-anchor" href="#onresize" aria-label="Permalink to &quot;onResize?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>onResize?</strong>: (<code>event</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L40" target="_blank" rel="noreferrer">host/types.ts:40</a></p><p>Called with a terminal resize, coalesced so a burst of SIGWINCH yields a single event.</p><h4 id="parameters-2" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-2" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="event-1" tabindex="-1">event <a class="header-anchor" href="#event-1" aria-label="Permalink to &quot;event&quot;">​</a></h5><p><a href="./ResizeEvent.html"><code>ResizeEvent</code></a></p><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="onresume" tabindex="-1">onResume? <a class="header-anchor" href="#onresume" aria-label="Permalink to &quot;onResume?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>onResume?</strong>: () =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L44" target="_blank" rel="noreferrer">host/types.ts:44</a></p><p>POSIX resume (SIGCONT): fired after modes are re-asserted and the last frame is repainted.</p><h4 id="returns-3" tabindex="-1">Returns <a class="header-anchor" href="#returns-3" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="onsuspend" tabindex="-1">onSuspend? <a class="header-anchor" href="#onsuspend" aria-label="Permalink to &quot;onSuspend?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>onSuspend?</strong>: () =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L42" target="_blank" rel="noreferrer">host/types.ts:42</a></p><p>POSIX Ctrl+Z (SIGTSTP): fired just before the terminal is restored and the process suspends.</p><h4 id="returns-4" tabindex="-1">Returns <a class="header-anchor" href="#returns-4" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="onwidthwarning" tabindex="-1">onWidthWarning? <a class="header-anchor" href="#onwidthwarning" aria-label="Permalink to &quot;onWidthWarning?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>onWidthWarning?</strong>: (<code>message</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L87" target="_blank" rel="noreferrer">host/types.ts:87</a></p><p>Where the startup width warning goes (see <a href="#warnambiguouswidth">warnAmbiguousWidth</a>). Default: one line to <code>process.stderr</code> (never the terminal&#39;s output stream). Provide your own to route it into a logger or custom reporting.</p><h4 id="parameters-3" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-3" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="message" tabindex="-1">message <a class="header-anchor" href="#message" aria-label="Permalink to &quot;message&quot;">​</a></h5><p><code>string</code></p><h4 id="returns-5" tabindex="-1">Returns <a class="header-anchor" href="#returns-5" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="output" tabindex="-1">output? <a class="header-anchor" href="#output" aria-label="Permalink to &quot;output?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>output?</strong>: <code>WriteStream</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L34" target="_blank" rel="noreferrer">host/types.ts:34</a></p><p>Output stream to render to. Default: <code>process.stdout</code> (or <code>/dev/tty</code> when piped).</p><hr><h3 id="preferdevtty" tabindex="-1">preferDevTty? <a class="header-anchor" href="#preferdevtty" aria-label="Permalink to &quot;preferDevTty?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>preferDevTty?</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L36" target="_blank" rel="noreferrer">host/types.ts:36</a></p><p>When true (default) and stdout is piped but a controlling terminal exists, bind to <code>/dev/tty</code>.</p><hr><h3 id="runtime" tabindex="-1">runtime? <a class="header-anchor" href="#runtime" aria-label="Permalink to &quot;runtime?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>runtime?</strong>: <a href="./RuntimeAdapter.html"><code>RuntimeAdapter</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L89" target="_blank" rel="noreferrer">host/types.ts:89</a></p><p>The OS boundary the host runs against. Defaults to the real Node runtime; inject a fake to test headlessly.</p><hr><h3 id="warnambiguouswidth" tabindex="-1">warnAmbiguousWidth? <a class="header-anchor" href="#warnambiguouswidth" aria-label="Permalink to &quot;warnAmbiguousWidth?&quot;">​</a></h3><blockquote><p><code>readonly</code> <code>optional</code> <strong>warnAmbiguousWidth?</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/75b321efad1a38e4c7d7579e7873170f363495fa/packages/core/src/engine/host/types.ts#L64" target="_blank" rel="noreferrer">host/types.ts:64</a></p><p>Probe the terminal at startup for double-width chrome glyphs — East-Asian <em>Ambiguous</em> code points (e.g. <code>▲◄■▒</code>) that a font fallback or CJK locale renders two cells wide, shifting box/scroll chrome — and warn via <a href="#onwidthwarning">onWidthWarning</a> when found. Real TTY only; runs after raw mode and before the alternate screen, so the probe and its erase stay off your UI. Default <code>false</code> (the higher-level app runner turns this on). Detection is best-effort — a silent or non-TTY terminal never warns.</p>',108)])])}const b=o(s,[["render",n]]);export{u as __pageData,b as default};
